#include <iostream>
#include <sstream>
#include <string>
#include <iomanip>

class Calculator {
public:
    int add(int a, int b) {
        return a + b;
    }
    double add(double a, double b) {
        return a + b;
    }
    float add(float a, float b) {
        return a + b;
    }
};

int main() {
    std::string line;
    std::cout << std::fixed << std::setprecision(6);
    Calculator calc;

    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        char type_char;
        ss >> type_char;

        if (type_char == 'i') {
            int a, b;
            ss >> a >> b;
            std::cout << calc.add(a, b) << std::endl;
        } else if (type_char == 'd') {
            double a, b;
            ss >> a >> b;
            std::cout << calc.add(a, b) << std::endl;
        }
    }
    return 0;
}
